def outlier_score(H):
    return (H.abs().mean(0) - H.abs().mean()) / H.abs().std()

def outlier_filter(H, threshold=3.0):
    return H[(outlier_score(H) < threshold)]

def outlier_remove(H, threshold=3.0):
    return H[~(outlier_score(H) > threshold)]

def outlier_fill(H, threshold=3.0):
    return H.fillna(H[~(outlier_score(H) > threshold)].mean())

def outlier_replace(H, threshold=3.0, value=0):
    return H.replace(H[outlier_score(H) > threshold], value)

def outlier_median(H, threshold=3.0):
    return H[~(outlier_score(H) > threshold)].median()

def outlier_mean(H, threshold=3.0):
    return H[~(outlier_score(H) > threshold)].mean()

def outlier_std(H, threshold=3.0):
    return H[~(outlier_score(H) > threshold)].std()

def outlier_quantile(H, threshold=3.0, q=0.05):
    return H[~(outlier_score(H) > threshold)].quantile(q)

def outlier_percentile(H, threshold=3.0, p=95):
    return H[~(outlier_score(H) > threshold)].percentile(p)

def outlier_interquartile(H, threshold=3.0):
    return H[~(outlier_score(H) > threshold)].quantile(0.75) - H[~(outlier_score(H) > threshold)].quantile(0.25)

